BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'PVD / PAD / DVT' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'PVD / PAD / DVT', 'Peripheral vascular disorders comparison and management', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - PVD/PAD/DVT (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'PVD PAD DVT - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports PVD umbrella concept in this vascular scenario?', 'Which finding best supports PVD umbrella concept in this vascular scenario?', '[{"id": "a", "text": "Peripheral vascular disease is an umbrella term that includes arterial and/or venous disorders."}, {"id": "b", "text": "PVD includes only pulmonary vessels in this note."}, {"id": "c", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "d", "text": "This pattern is more consistent with ABI threshold."}]'::jsonb, '["a"]'::jsonb, 'Correct because Peripheral vascular disease is an umbrella term that includes arterial and/or venous disorders. Differentiate arterial from venous findings before intervention.', 'PVD PAD DVT - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes assessment data. Which interpretation best matches PAD definition?', 'The nurse analyzes assessment data. Which interpretation best matches PAD definition?', '[{"id": "a", "text": "Recognize ischemic limb signs and perfusion threats early."}, {"id": "b", "text": "PAD is caused by pulmonary emboli in this note."}, {"id": "c", "text": "PAD is venous valve failure in this note."}, {"id": "d", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}]'::jsonb, '["a"]'::jsonb, 'Correct because Peripheral arterial disease is arterial narrowing from atherosclerosis causing reduced blood flow. Recognize ischemic limb signs and perfusion threats early.', 'PVD PAD DVT - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding DVT definition?', 'Which clinical judgment is most accurate regarding DVT definition?', '[{"id": "a", "text": "DVT has no embolic risk in this note."}, {"id": "b", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "c", "text": "This pattern is more consistent with Buerger-Allen test."}, {"id": "d", "text": "Deep vein thrombosis is thrombus formation in deep veins, usually leg, with pulmonary embolism risk."}]'::jsonb, '["d"]'::jsonb, 'Correct because Deep vein thrombosis is thrombus formation in deep veins, usually leg, with pulmonary embolism risk. Prevent embolization and monitor for PE deterioration.', 'PVD PAD DVT - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Venous insufficiency signs?', 'In urgent triage, which conclusion aligns with Venous insufficiency signs?', '[{"id": "a", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "b", "text": "Cool hairless skin is classic venous profile in this note."}, {"id": "c", "text": "Use skin temperature/pulse pattern to separate venous from arterial disease."}, {"id": "d", "text": "Absent pulses are hallmark venous insufficiency sign in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Venous insufficiency signs include varicosities, edema, brown hemosiderin skin changes, warm moist skin, and pulses present. Use skin temperature/pulse pattern to separate venous from arterial disease.', 'PVD PAD DVT - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Venous stasis ulcer profile?', 'Which statement most appropriately reflects Venous stasis ulcer profile?', '[{"id": "a", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "b", "text": "Venous ulcers are punched-out lateral toe lesions in this note."}, {"id": "c", "text": "This pattern is more consistent with Virchow triad overview."}, {"id": "d", "text": "Venous ulcers are usually at medial malleolus, irregular edges, and often painless."}]'::jsonb, '["d"]'::jsonb, 'Correct because Venous ulcers are usually at medial malleolus, irregular edges, and often painless. Correct ulcer classification guides positioning and wound strategy.', 'PVD PAD DVT - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports PAD symptom hallmark in this vascular scenario?', 'Which finding best supports PAD symptom hallmark in this vascular scenario?', '[{"id": "a", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "b", "text": "This pattern is more consistent with Stasis examples."}, {"id": "c", "text": "Progression from exertional pain to rest pain signals worsening ischemia."}, {"id": "d", "text": "PAD pain improves with walking in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Intermittent claudication is leg pain with walking relieved by rest; advanced disease may cause rest pain. Progression from exertional pain to rest pain signals worsening ischemia.', 'PVD PAD DVT - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes assessment data. Which interpretation best matches ABI threshold?', 'The nurse analyzes assessment data. Which interpretation best matches ABI threshold?', '[{"id": "a", "text": "Ankle-brachial index below 0.9 supports PAD diagnosis."}, {"id": "b", "text": "This pattern is more consistent with Hypercoagulability examples."}, {"id": "c", "text": "ABI is not used for PAD in this note."}, {"id": "d", "text": "Pulses do not need reassessment after vascular interventions."}]'::jsonb, '["a"]'::jsonb, 'Correct because Ankle-brachial index below 0.9 supports PAD diagnosis. Use ABI to quantify arterial perfusion deficit objectively.', 'PVD PAD DVT - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding 6 Ps arterial emergency?', 'Which clinical judgment is most accurate regarding 6 Ps arterial emergency?', '[{"id": "a", "text": "6 Ps indicate stable chronic venous disease in this note."}, {"id": "b", "text": "Treat 6 Ps as limb-threatening emergency requiring immediate escalation."}, {"id": "c", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "d", "text": "This pattern is more consistent with Endothelial injury examples."}]'::jsonb, '["b"]'::jsonb, 'Correct because Acute arterial occlusion signs are pain, pallor, pulselessness, paresthesia, poikilothermia, and paralysis. Treat 6 Ps as limb-threatening emergency requiring immediate escalation.', 'PVD PAD DVT - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Buerger-Allen test?', 'In urgent triage, which conclusion aligns with Buerger-Allen test?', '[{"id": "a", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "b", "text": "In Buerger-Allen test, leg elevation causing pallor then dependent rubor supports PAD."}, {"id": "c", "text": "No color change is required for positive test in this note."}, {"id": "d", "text": "This pattern is more consistent with DVT signs."}]'::jsonb, '["b"]'::jsonb, 'Correct because In Buerger-Allen test, leg elevation causing pallor then dependent rubor supports PAD. Interpret positional color changes as arterial insufficiency evidence.', 'PVD PAD DVT - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects PAD management essentials?', 'Which statement most appropriately reflects PAD management essentials?', '[{"id": "a", "text": "Combine risk modification and perfusion restoration interventions."}, {"id": "b", "text": "Smoking has no effect on PAD outcomes in this note."}, {"id": "c", "text": "PAD legs should always be elevated high in this note."}, {"id": "d", "text": "Pulses do not need reassessment after vascular interventions."}]'::jsonb, '["a"]'::jsonb, 'Correct because PAD management includes smoking cessation priority, antiplatelets, supervised walking, revascularization, and dependent leg positioning. Combine risk modification and perfusion restoration interventions.', 'PVD PAD DVT - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Virchow triad overview in this vascular scenario?', 'Which finding best supports Virchow triad overview in this vascular scenario?', '[{"id": "a", "text": "This pattern is more consistent with PE deterioration clue."}, {"id": "b", "text": "DVT causes follow Virchow triad: stasis, hypercoagulability, and endothelial injury."}, {"id": "c", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "d", "text": "Hypothermia is a Virchow component in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because DVT causes follow Virchow triad: stasis, hypercoagulability, and endothelial injury. Identify which triad component is present to target prevention.', 'PVD PAD DVT - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes assessment data. Which interpretation best matches Stasis examples?', 'The nurse analyzes assessment data. Which interpretation best matches Stasis examples?', '[{"id": "a", "text": "Early mobilization plans reduce stasis-driven thrombosis risk."}, {"id": "b", "text": "Stasis is unrelated to DVT in this note."}, {"id": "c", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "d", "text": "Frequent ambulation is stasis cause in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Stasis examples listed include immobility, long flights, and post-op state. Early mobilization plans reduce stasis-driven thrombosis risk.', 'PVD PAD DVT - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Hypercoagulability examples?', 'Which clinical judgment is most accurate regarding Hypercoagulability examples?', '[{"id": "a", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "b", "text": "Cancer lowers DVT risk in this note."}, {"id": "c", "text": "Hypercoagulability risks listed include oral contraceptives, cancer, and clotting disorders."}, {"id": "d", "text": "Hypercoagulability excludes medication effects in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Hypercoagulability risks listed include oral contraceptives, cancer, and clotting disorders. Screen thrombosis history and prothrombotic exposures carefully.', 'PVD PAD DVT - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Endothelial injury examples?', 'In urgent triage, which conclusion aligns with Endothelial injury examples?', '[{"id": "a", "text": "Protect vessel integrity and monitor post-procedural patients."}, {"id": "b", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "c", "text": "Intact endothelium is risk factor in this note."}, {"id": "d", "text": "Only diet causes endothelial injury in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Endothelial injury examples include trauma, surgery, and catheters. Protect vessel integrity and monitor post-procedural patients.', 'PVD PAD DVT - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects DVT signs?', 'Which statement most appropriately reflects DVT signs?', '[{"id": "a", "text": "DVT signs include unilateral calf pain/tenderness, unilateral edema, warmth, redness, and possible low-grade fever."}, {"id": "b", "text": "DVT typically causes absent pulses as first sign in this note."}, {"id": "c", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "d", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}]'::jsonb, '["a"]'::jsonb, 'Correct because DVT signs include unilateral calf pain/tenderness, unilateral edema, warmth, redness, and possible low-grade fever. Unilateral inflammatory limb signs should trigger urgent DVT evaluation.', 'PVD PAD DVT - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Homans sign caution in this vascular scenario?', 'Which finding best supports Homans sign caution in this vascular scenario?', '[{"id": "a", "text": "Rely on modern diagnostics rather than outdated bedside signs."}, {"id": "b", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "c", "text": "Homans is mandatory for all exams in this note."}, {"id": "d", "text": "Pulses do not need reassessment after vascular interventions."}]'::jsonb, '["a"]'::jsonb, 'Correct because Homans sign is noted as unreliable and rarely tested now. Rely on modern diagnostics rather than outdated bedside signs.', 'PVD PAD DVT - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes assessment data. Which interpretation best matches PE deterioration clue?', 'The nurse analyzes assessment data. Which interpretation best matches PE deterioration clue?', '[{"id": "a", "text": "DVT can embolize causing PE with sudden dyspnea, chest pain, hypoxia, and tachycardia."}, {"id": "b", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "c", "text": "PE presents only with slow asymptomatic edema in this note."}, {"id": "d", "text": "PE risk is absent after DVT diagnosis in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because DVT can embolize causing PE with sudden dyspnea, chest pain, hypoxia, and tachycardia. Sudden respiratory decline in DVT patient is emergency PE suspicion.', 'PVD PAD DVT - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding DVT anticoagulation?', 'Which clinical judgment is most accurate regarding DVT anticoagulation?', '[{"id": "a", "text": "This pattern is more consistent with Key nursing NCLEX points."}, {"id": "b", "text": "Anticoagulation is limited to one day in this note."}, {"id": "c", "text": "Ensure transition from acute to maintenance anticoagulation safely."}, {"id": "d", "text": "Pulses do not need reassessment after vascular interventions."}]'::jsonb, '["c"]'::jsonb, 'Correct because DVT treatment starts with heparin acutely then warfarin or NOAC for 3–6 months. Ensure transition from acute to maintenance anticoagulation safely.', 'PVD PAD DVT - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with DVT supportive care?', 'In urgent triage, which conclusion aligns with DVT supportive care?', '[{"id": "a", "text": "Leg dependency is preferred for DVT edema in this note."}, {"id": "b", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "c", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "d", "text": "Supportive care includes leg elevation above heart, compression stockings, and early ambulation once anticoagulated."}]'::jsonb, '["d"]'::jsonb, 'Correct because Supportive care includes leg elevation above heart, compression stockings, and early ambulation once anticoagulated. Balance clot stabilization with circulation/mobility support.', 'PVD PAD DVT - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects IVC filter indication?', 'Which statement most appropriately reflects IVC filter indication?', '[{"id": "a", "text": "IVC filters are only for arterial occlusion in this note."}, {"id": "b", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "c", "text": "Use mechanical embolic protection when anticoagulation cannot be used."}, {"id": "d", "text": "Pulses do not need reassessment after vascular interventions."}]'::jsonb, '["c"]'::jsonb, 'Correct because IVC filter is considered if anticoagulation is contraindicated. Use mechanical embolic protection when anticoagulation cannot be used.', 'PVD PAD DVT - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Arterial ulcer profile in this vascular scenario?', 'Which finding best supports Arterial ulcer profile in this vascular scenario?', '[{"id": "a", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "b", "text": "Arterial ulcers are warm moist and painless in this note."}, {"id": "c", "text": "This pattern is more consistent with DVT definition."}, {"id": "d", "text": "Arterial ulcers are on toes/lateral malleolus/foot, very painful, punched-out, pale/necrotic, with diminished/absent pulses and cool hairless skin."}]'::jsonb, '["d"]'::jsonb, 'Correct because Arterial ulcers are on toes/lateral malleolus/foot, very painful, punched-out, pale/necrotic, with diminished/absent pulses and cool hairless skin. Identify ischemic ulcer features to prevent limb loss.', 'PVD PAD DVT - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes assessment data. Which interpretation best matches Venous ulcer profile?', 'The nurse analyzes assessment data. Which interpretation best matches Venous ulcer profile?', '[{"id": "a", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "b", "text": "Use venous profile to prioritize elevation and compression strategies."}, {"id": "c", "text": "Venous ulcers are lateral toe punched-out lesions in this note."}, {"id": "d", "text": "This pattern is more consistent with Venous insufficiency signs."}]'::jsonb, '["b"]'::jsonb, 'Correct because Venous ulcers are medial malleolus, irregular/ragged, granulating/ruddy, warm edematous skin with pulses present. Use venous profile to prioritize elevation and compression strategies.', 'PVD PAD DVT - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Positioning contrast?', 'Which clinical judgment is most accurate regarding Positioning contrast?', '[{"id": "a", "text": "PAD requires leg elevation above heart in this note."}, {"id": "b", "text": "Arterial disease benefits from dependent legs, while venous disease benefits from elevation to reduce pooling."}, {"id": "c", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "d", "text": "This pattern is more consistent with Venous stasis ulcer profile."}]'::jsonb, '["b"]'::jsonb, 'Correct because Arterial disease benefits from dependent legs, while venous disease benefits from elevation to reduce pooling. Correct positioning is immediate, high-yield bedside intervention.', 'PVD PAD DVT - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Key nursing NCLEX points?', 'In urgent triage, which conclusion aligns with Key nursing NCLEX points?', '[{"id": "a", "text": "Massaging DVT leg is recommended to improve flow in this note."}, {"id": "b", "text": "This pattern is more consistent with PAD symptom hallmark."}, {"id": "c", "text": "Avoid embolization and identify limb-threatening ischemia rapidly."}, {"id": "d", "text": "Pulses do not need reassessment after vascular interventions."}]'::jsonb, '["c"]'::jsonb, 'Correct because Do not massage suspected DVT leg, assess pulses pre/post interventions, prevent DVT with ambulation/compression/anticoagulation post-op, and treat 6 Ps as arterial emergency. Avoid embolization and identify limb-threatening ischemia rapidly.', 'PVD PAD DVT - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects PVD umbrella concept?', 'Which statement most appropriately reflects PVD umbrella concept?', '[{"id": "a", "text": "This pattern is more consistent with ABI threshold."}, {"id": "b", "text": "PVD includes only pulmonary vessels in this note."}, {"id": "c", "text": "PVD excludes venous disease in this note."}, {"id": "d", "text": "Peripheral vascular disease is an umbrella term that includes arterial and/or venous disorders."}]'::jsonb, '["d"]'::jsonb, 'Correct because Peripheral vascular disease is an umbrella term that includes arterial and/or venous disorders. Differentiate arterial from venous findings before intervention.', 'PVD PAD DVT - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports PAD definition in this vascular scenario?', 'Which finding best supports PAD definition in this vascular scenario?', '[{"id": "a", "text": "Recognize ischemic limb signs and perfusion threats early."}, {"id": "b", "text": "This pattern is more consistent with 6 Ps arterial emergency."}, {"id": "c", "text": "PAD is venous valve failure in this note."}, {"id": "d", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}]'::jsonb, '["a"]'::jsonb, 'Correct because Peripheral arterial disease is arterial narrowing from atherosclerosis causing reduced blood flow. Recognize ischemic limb signs and perfusion threats early.', 'PVD PAD DVT - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes assessment data. Which interpretation best matches DVT definition?', 'The nurse analyzes assessment data. Which interpretation best matches DVT definition?', '[{"id": "a", "text": "This pattern is more consistent with Buerger-Allen test."}, {"id": "b", "text": "DVT is primarily arterial plaque rupture in this note."}, {"id": "c", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "d", "text": "Deep vein thrombosis is thrombus formation in deep veins, usually leg, with pulmonary embolism risk."}]'::jsonb, '["d"]'::jsonb, 'Correct because Deep vein thrombosis is thrombus formation in deep veins, usually leg, with pulmonary embolism risk. Prevent embolization and monitor for PE deterioration.', 'PVD PAD DVT - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Venous insufficiency signs?', 'Which clinical judgment is most accurate regarding Venous insufficiency signs?', '[{"id": "a", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "b", "text": "This pattern is more consistent with PAD management essentials."}, {"id": "c", "text": "Absent pulses are hallmark venous insufficiency sign in this note."}, {"id": "d", "text": "Use skin temperature/pulse pattern to separate venous from arterial disease."}]'::jsonb, '["d"]'::jsonb, 'Correct because Venous insufficiency signs include varicosities, edema, brown hemosiderin skin changes, warm moist skin, and pulses present. Use skin temperature/pulse pattern to separate venous from arterial disease.', 'PVD PAD DVT - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with Venous stasis ulcer profile?', 'In urgent triage, which conclusion aligns with Venous stasis ulcer profile?', '[{"id": "a", "text": "Venous ulcers are always severe pain in this note."}, {"id": "b", "text": "Venous ulcers are punched-out lateral toe lesions in this note."}, {"id": "c", "text": "This pattern is more consistent with Virchow triad overview."}, {"id": "d", "text": "Venous ulcers are usually at medial malleolus, irregular edges, and often painless."}]'::jsonb, '["d"]'::jsonb, 'Correct because Venous ulcers are usually at medial malleolus, irregular edges, and often painless. Correct ulcer classification guides positioning and wound strategy.', 'PVD PAD DVT - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects PAD symptom hallmark?', 'Which statement most appropriately reflects PAD symptom hallmark?', '[{"id": "a", "text": "Progression from exertional pain to rest pain signals worsening ischemia."}, {"id": "b", "text": "PAD never causes rest pain in this note."}, {"id": "c", "text": "PAD pain improves with walking in this note."}, {"id": "d", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}]'::jsonb, '["a"]'::jsonb, 'Correct because Intermittent claudication is leg pain with walking relieved by rest; advanced disease may cause rest pain. Progression from exertional pain to rest pain signals worsening ischemia.', 'PVD PAD DVT - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports ABI threshold in this vascular scenario?', 'Which finding best supports ABI threshold in this vascular scenario?', '[{"id": "a", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "b", "text": "This pattern is more consistent with Hypercoagulability examples."}, {"id": "c", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "d", "text": "Ankle-brachial index below 0.9 supports PAD diagnosis."}]'::jsonb, '["d"]'::jsonb, 'Correct because Ankle-brachial index below 0.9 supports PAD diagnosis. Use ABI to quantify arterial perfusion deficit objectively.', 'PVD PAD DVT - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes assessment data. Which interpretation best matches 6 Ps arterial emergency?', 'The nurse analyzes assessment data. Which interpretation best matches 6 Ps arterial emergency?', '[{"id": "a", "text": "This pattern is more consistent with Endothelial injury examples."}, {"id": "b", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "c", "text": "Treat 6 Ps as limb-threatening emergency requiring immediate escalation."}, {"id": "d", "text": "6 Ps indicate stable chronic venous disease in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Acute arterial occlusion signs are pain, pallor, pulselessness, paresthesia, poikilothermia, and paralysis. Treat 6 Ps as limb-threatening emergency requiring immediate escalation.', 'PVD PAD DVT - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Buerger-Allen test?', 'Which clinical judgment is most accurate regarding Buerger-Allen test?', '[{"id": "a", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "b", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "c", "text": "No color change is required for positive test in this note."}, {"id": "d", "text": "In Buerger-Allen test, leg elevation causing pallor then dependent rubor supports PAD."}]'::jsonb, '["d"]'::jsonb, 'Correct because In Buerger-Allen test, leg elevation causing pallor then dependent rubor supports PAD. Interpret positional color changes as arterial insufficiency evidence.', 'PVD PAD DVT - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with PAD management essentials?', 'In urgent triage, which conclusion aligns with PAD management essentials?', '[{"id": "a", "text": "Combine risk modification and perfusion restoration interventions."}, {"id": "b", "text": "Smoking has no effect on PAD outcomes in this note."}, {"id": "c", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "d", "text": "PAD legs should always be elevated high in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because PAD management includes smoking cessation priority, antiplatelets, supervised walking, revascularization, and dependent leg positioning. Combine risk modification and perfusion restoration interventions.', 'PVD PAD DVT - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Virchow triad overview?', 'Which statement most appropriately reflects Virchow triad overview?', '[{"id": "a", "text": "Hypothermia is a Virchow component in this note."}, {"id": "b", "text": "DVT causes follow Virchow triad: stasis, hypercoagulability, and endothelial injury."}, {"id": "c", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "d", "text": "Pulses do not need reassessment after vascular interventions."}]'::jsonb, '["b"]'::jsonb, 'Correct because DVT causes follow Virchow triad: stasis, hypercoagulability, and endothelial injury. Identify which triad component is present to target prevention.', 'PVD PAD DVT - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Stasis examples in this vascular scenario?', 'Which finding best supports Stasis examples in this vascular scenario?', '[{"id": "a", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "b", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "c", "text": "Stasis is unrelated to DVT in this note."}, {"id": "d", "text": "Early mobilization plans reduce stasis-driven thrombosis risk."}]'::jsonb, '["d"]'::jsonb, 'Correct because Stasis examples listed include immobility, long flights, and post-op state. Early mobilization plans reduce stasis-driven thrombosis risk.', 'PVD PAD DVT - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes assessment data. Which interpretation best matches Hypercoagulability examples?', 'The nurse analyzes assessment data. Which interpretation best matches Hypercoagulability examples?', '[{"id": "a", "text": "This pattern is more consistent with DVT supportive care."}, {"id": "b", "text": "Hypercoagulability risks listed include oral contraceptives, cancer, and clotting disorders."}, {"id": "c", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "d", "text": "Cancer lowers DVT risk in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Hypercoagulability risks listed include oral contraceptives, cancer, and clotting disorders. Screen thrombosis history and prothrombotic exposures carefully.', 'PVD PAD DVT - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Endothelial injury examples?', 'Which clinical judgment is most accurate regarding Endothelial injury examples?', '[{"id": "a", "text": "Intact endothelium is risk factor in this note."}, {"id": "b", "text": "Only diet causes endothelial injury in this note."}, {"id": "c", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "d", "text": "Protect vessel integrity and monitor post-procedural patients."}]'::jsonb, '["d"]'::jsonb, 'Correct because Endothelial injury examples include trauma, surgery, and catheters. Protect vessel integrity and monitor post-procedural patients.', 'PVD PAD DVT - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with DVT signs?', 'In urgent triage, which conclusion aligns with DVT signs?', '[{"id": "a", "text": "DVT signs include unilateral calf pain/tenderness, unilateral edema, warmth, redness, and possible low-grade fever."}, {"id": "b", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "c", "text": "Bilateral cool pale legs are hallmark DVT sign in this note."}, {"id": "d", "text": "DVT typically causes absent pulses as first sign in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because DVT signs include unilateral calf pain/tenderness, unilateral edema, warmth, redness, and possible low-grade fever. Unilateral inflammatory limb signs should trigger urgent DVT evaluation.', 'PVD PAD DVT - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Homans sign caution?', 'Which statement most appropriately reflects Homans sign caution?', '[{"id": "a", "text": "Homans is mandatory for all exams in this note."}, {"id": "b", "text": "This pattern is more consistent with Venous ulcer profile."}, {"id": "c", "text": "Rely on modern diagnostics rather than outdated bedside signs."}, {"id": "d", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}]'::jsonb, '["c"]'::jsonb, 'Correct because Homans sign is noted as unreliable and rarely tested now. Rely on modern diagnostics rather than outdated bedside signs.', 'PVD PAD DVT - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports PE deterioration clue in this vascular scenario?', 'Which finding best supports PE deterioration clue in this vascular scenario?', '[{"id": "a", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "b", "text": "DVT can embolize causing PE with sudden dyspnea, chest pain, hypoxia, and tachycardia."}, {"id": "c", "text": "PE presents only with slow asymptomatic edema in this note."}, {"id": "d", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}]'::jsonb, '["b"]'::jsonb, 'Correct because DVT can embolize causing PE with sudden dyspnea, chest pain, hypoxia, and tachycardia. Sudden respiratory decline in DVT patient is emergency PE suspicion.', 'PVD PAD DVT - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes assessment data. Which interpretation best matches DVT anticoagulation?', 'The nurse analyzes assessment data. Which interpretation best matches DVT anticoagulation?', '[{"id": "a", "text": "Ensure transition from acute to maintenance anticoagulation safely."}, {"id": "b", "text": "This pattern is more consistent with Key nursing NCLEX points."}, {"id": "c", "text": "DVT is treated with antiplatelet only in this note."}, {"id": "d", "text": "Pulses do not need reassessment after vascular interventions."}]'::jsonb, '["a"]'::jsonb, 'Correct because DVT treatment starts with heparin acutely then warfarin or NOAC for 3–6 months. Ensure transition from acute to maintenance anticoagulation safely.', 'PVD PAD DVT - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding DVT supportive care?', 'Which clinical judgment is most accurate regarding DVT supportive care?', '[{"id": "a", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "b", "text": "Supportive care includes leg elevation above heart, compression stockings, and early ambulation once anticoagulated."}, {"id": "c", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "d", "text": "Leg dependency is preferred for DVT edema in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Supportive care includes leg elevation above heart, compression stockings, and early ambulation once anticoagulated. Balance clot stabilization with circulation/mobility support.', 'PVD PAD DVT - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with IVC filter indication?', 'In urgent triage, which conclusion aligns with IVC filter indication?', '[{"id": "a", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "b", "text": "Use mechanical embolic protection when anticoagulation cannot be used."}, {"id": "c", "text": "IVC filters are only for arterial occlusion in this note."}, {"id": "d", "text": "Pulses do not need reassessment after vascular interventions."}]'::jsonb, '["b"]'::jsonb, 'Correct because IVC filter is considered if anticoagulation is contraindicated. Use mechanical embolic protection when anticoagulation cannot be used.', 'PVD PAD DVT - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects Arterial ulcer profile?', 'Which statement most appropriately reflects Arterial ulcer profile?', '[{"id": "a", "text": "Arterial ulcers are warm moist and painless in this note."}, {"id": "b", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "c", "text": "This pattern is more consistent with DVT definition."}, {"id": "d", "text": "Arterial ulcers are on toes/lateral malleolus/foot, very painful, punched-out, pale/necrotic, with diminished/absent pulses and cool hairless skin."}]'::jsonb, '["d"]'::jsonb, 'Correct because Arterial ulcers are on toes/lateral malleolus/foot, very painful, punched-out, pale/necrotic, with diminished/absent pulses and cool hairless skin. Identify ischemic ulcer features to prevent limb loss.', 'PVD PAD DVT - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding best supports Venous ulcer profile in this vascular scenario?', 'Which finding best supports Venous ulcer profile in this vascular scenario?', '[{"id": "a", "text": "Venous ulcers are lateral toe punched-out lesions in this note."}, {"id": "b", "text": "Venous ulcers have absent pulses and pale necrotic bed in this note."}, {"id": "c", "text": "Use venous profile to prioritize elevation and compression strategies."}, {"id": "d", "text": "This pattern is more consistent with Venous insufficiency signs."}]'::jsonb, '["c"]'::jsonb, 'Correct because Venous ulcers are medial malleolus, irregular/ragged, granulating/ruddy, warm edematous skin with pulses present. Use venous profile to prioritize elevation and compression strategies.', 'PVD PAD DVT - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse analyzes assessment data. Which interpretation best matches Positioning contrast?', 'The nurse analyzes assessment data. Which interpretation best matches Positioning contrast?', '[{"id": "a", "text": "Arterial disease benefits from dependent legs, while venous disease benefits from elevation to reduce pooling."}, {"id": "b", "text": "This pattern is more consistent with Venous stasis ulcer profile."}, {"id": "c", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "d", "text": "PAD requires leg elevation above heart in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Arterial disease benefits from dependent legs, while venous disease benefits from elevation to reduce pooling. Correct positioning is immediate, high-yield bedside intervention.', 'PVD PAD DVT - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate regarding Key nursing NCLEX points?', 'Which clinical judgment is most accurate regarding Key nursing NCLEX points?', '[{"id": "a", "text": "Avoid embolization and identify limb-threatening ischemia rapidly."}, {"id": "b", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "c", "text": "6 Ps can be observed without escalation in this note."}, {"id": "d", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}]'::jsonb, '["a"]'::jsonb, 'Correct because Do not massage suspected DVT leg, assess pulses pre/post interventions, prevent DVT with ambulation/compression/anticoagulation post-op, and treat 6 Ps as arterial emergency. Avoid embolization and identify limb-threatening ischemia rapidly.', 'PVD PAD DVT - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent triage, which conclusion aligns with PVD umbrella concept?', 'In urgent triage, which conclusion aligns with PVD umbrella concept?', '[{"id": "a", "text": "Pulses do not need reassessment after vascular interventions."}, {"id": "b", "text": "PVD excludes venous disease in this note."}, {"id": "c", "text": "PVD includes only pulmonary vessels in this note."}, {"id": "d", "text": "Peripheral vascular disease is an umbrella term that includes arterial and/or venous disorders."}]'::jsonb, '["d"]'::jsonb, 'Correct because Peripheral vascular disease is an umbrella term that includes arterial and/or venous disorders. Differentiate arterial from venous findings before intervention.', 'PVD PAD DVT - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement most appropriately reflects PAD definition?', 'Which statement most appropriately reflects PAD definition?', '[{"id": "a", "text": "Recognize ischemic limb signs and perfusion threats early."}, {"id": "b", "text": "This pattern is more consistent with 6 Ps arterial emergency."}, {"id": "c", "text": "Immediate escalation is unnecessary unless bilateral symptoms are present."}, {"id": "d", "text": "PAD is venous valve failure in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Peripheral arterial disease is arterial narrowing from atherosclerosis causing reduced blood flow. Recognize ischemic limb signs and perfusion threats early.', 'PVD PAD DVT - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for PVD umbrella concept. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for PVD umbrella concept. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Venous disease can also fall under PVD."}, {"id": "b", "text": "PAD is within broader PVD category."}, {"id": "c", "text": "PVD excludes venous disease in this note."}, {"id": "d", "text": "PVD can involve arteries and veins."}, {"id": "e", "text": "PVD includes only pulmonary vessels in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Peripheral vascular disease is an umbrella term that includes arterial and/or venous disorders.', 'PVD PAD DVT - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving PAD definition, which statements are correct? (Select all that apply)', 'For care involving PAD definition, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Atherosclerosis is core mechanism in PAD."}, {"id": "b", "text": "Reduced distal flow causes ischemic symptoms."}, {"id": "c", "text": "PAD is caused by pulmonary emboli in this note."}, {"id": "d", "text": "PAD is arterial only in this note."}, {"id": "e", "text": "PAD is venous valve failure in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Peripheral arterial disease is arterial narrowing from atherosclerosis causing reduced blood flow.', 'PVD PAD DVT - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions for DVT definition. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions for DVT definition. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "DVT is venous clot disease."}, {"id": "b", "text": "DVT is primarily arterial plaque rupture in this note."}, {"id": "c", "text": "Thrombus embolization can cause PE."}, {"id": "d", "text": "DVT has no embolic risk in this note."}, {"id": "e", "text": "DVT usually occurs in deep leg veins."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Deep vein thrombosis is thrombus formation in deep veins, usually leg, with pulmonary embolism risk.', 'PVD PAD DVT - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Venous insufficiency signs? (Select all that apply)', 'During reassessment, which observations support Venous insufficiency signs? (Select all that apply)', '[{"id": "a", "text": "Pulses are generally present in venous insufficiency."}, {"id": "b", "text": "Brown pigmentation is venous finding."}, {"id": "c", "text": "Warm moist skin suggests venous disease."}, {"id": "d", "text": "Absent pulses are hallmark venous insufficiency sign in this note."}, {"id": "e", "text": "Cool hairless skin is classic venous profile in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Venous insufficiency signs include varicosities, edema, brown hemosiderin skin changes, warm moist skin, and pulses present.', 'PVD PAD DVT - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Venous stasis ulcer profile in this note? (Select all that apply)', 'Which clues are consistent with Venous stasis ulcer profile in this note? (Select all that apply)', '[{"id": "a", "text": "Medial malleolus location suggests venous ulcer."}, {"id": "b", "text": "Venous ulcers are always severe pain in this note."}, {"id": "c", "text": "Venous ulcers are punched-out lateral toe lesions in this note."}, {"id": "d", "text": "Venous ulcer pain is often mild or absent."}, {"id": "e", "text": "Venous ulcer edges are irregular/ragged."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Venous ulcers are usually at medial malleolus, irregular edges, and often painless.', 'PVD PAD DVT - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for PAD symptom hallmark. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for PAD symptom hallmark. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Rest relieves claudication in earlier PAD."}, {"id": "b", "text": "PAD never causes rest pain in this note."}, {"id": "c", "text": "Rest pain indicates advanced disease in note."}, {"id": "d", "text": "Claudication appears with activity in PAD."}, {"id": "e", "text": "PAD pain improves with walking in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Intermittent claudication is leg pain with walking relieved by rest; advanced disease may cause rest pain.', 'PVD PAD DVT - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving ABI threshold, which statements are correct? (Select all that apply)', 'For care involving ABI threshold, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "ABI is listed PAD assessment tool."}, {"id": "b", "text": "ABI >1.5 confirms PAD in this note."}, {"id": "c", "text": "ABI compares ankle and brachial pressures."}, {"id": "d", "text": "ABI is not used for PAD in this note."}, {"id": "e", "text": "ABI <0.9 is abnormal for PAD in note."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Ankle-brachial index below 0.9 supports PAD diagnosis.', 'PVD PAD DVT - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions for 6 Ps arterial emergency. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions for 6 Ps arterial emergency. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Pulselessness and paresthesia are in 6 Ps."}, {"id": "b", "text": "Poikilothermia and paralysis are in 6 Ps."}, {"id": "c", "text": "Pain and pallor are in 6 Ps."}, {"id": "d", "text": "6 Ps indicate stable chronic venous disease in this note."}, {"id": "e", "text": "Pitting edema replaces pulselessness in 6 Ps in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Acute arterial occlusion signs are pain, pallor, pulselessness, paresthesia, poikilothermia, and paralysis.', 'PVD PAD DVT - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Buerger-Allen test? (Select all that apply)', 'During reassessment, which observations support Buerger-Allen test? (Select all that apply)', '[{"id": "a", "text": "Buerger test confirms DVT in this note."}, {"id": "b", "text": "No color change is required for positive test in this note."}, {"id": "c", "text": "Test is listed under PAD assessment."}, {"id": "d", "text": "Elevation pallor is PAD clue in this test."}, {"id": "e", "text": "Dependent rubor supports PAD in this test."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: In Buerger-Allen test, leg elevation causing pallor then dependent rubor supports PAD.', 'PVD PAD DVT - NCLEX', true, 59, 1, true);
