  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with PAD management essentials in this note? (Select all that apply)', 'Which clues are consistent with PAD management essentials in this note? (Select all that apply)', '[{"id": "a", "text": "Legs dependent can improve arterial flow."}, {"id": "b", "text": "PAD legs should always be elevated high in this note."}, {"id": "c", "text": "Smoking has no effect on PAD outcomes in this note."}, {"id": "d", "text": "Aspirin/clopidogrel are listed PAD meds."}, {"id": "e", "text": "Smoking cessation is absolute priority in PAD note."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: PAD management includes smoking cessation priority, antiplatelets, supervised walking, revascularization, and dependent leg positioning.', 'PVD PAD DVT - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Virchow triad overview. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Virchow triad overview. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Hypercoagulability is a Virchow component."}, {"id": "b", "text": "Stasis is a Virchow component."}, {"id": "c", "text": "Endothelial damage is a Virchow component."}, {"id": "d", "text": "Hypothermia is a Virchow component in this note."}, {"id": "e", "text": "Virchow triad applies only to arterial disease in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: DVT causes follow Virchow triad: stasis, hypercoagulability, and endothelial injury.', 'PVD PAD DVT - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving Stasis examples, which statements are correct? (Select all that apply)', 'For care involving Stasis examples, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Long flights are stasis risk in note."}, {"id": "b", "text": "Stasis is unrelated to DVT in this note."}, {"id": "c", "text": "Frequent ambulation is stasis cause in this note."}, {"id": "d", "text": "Post-op state can contribute to stasis."}, {"id": "e", "text": "Immobility is stasis risk in note."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Stasis examples listed include immobility, long flights, and post-op state.', 'PVD PAD DVT - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions for Hypercoagulability examples. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions for Hypercoagulability examples. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Hypercoagulability excludes medication effects in this note."}, {"id": "b", "text": "Inherited/acquired clotting disorders are listed."}, {"id": "c", "text": "Cancer is listed hypercoagulability risk."}, {"id": "d", "text": "Oral contraceptives are listed hypercoagulability risk."}, {"id": "e", "text": "Cancer lowers DVT risk in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Hypercoagulability risks listed include oral contraceptives, cancer, and clotting disorders.', 'PVD PAD DVT - NCLEX', true, 63, 1, true);
