  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Endothelial injury examples? (Select all that apply)', 'During reassessment, which observations support Endothelial injury examples? (Select all that apply)', '[{"id": "a", "text": "Only diet causes endothelial injury in this note."}, {"id": "b", "text": "Intact endothelium is risk factor in this note."}, {"id": "c", "text": "Surgery is endothelial injury risk."}, {"id": "d", "text": "Trauma is endothelial injury risk."}, {"id": "e", "text": "Catheter-related injury is listed risk."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Endothelial injury examples include trauma, surgery, and catheters.', 'PVD PAD DVT - NCLEX', true, 64, 1, true);
