  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with DVT signs in this note? (Select all that apply)', 'Which clues are consistent with DVT signs in this note? (Select all that apply)', '[{"id": "a", "text": "Low-grade fever may be present."}, {"id": "b", "text": "Unilateral swelling is classic DVT clue."}, {"id": "c", "text": "Warmth/redness can occur in DVT."}, {"id": "d", "text": "Bilateral cool pale legs are hallmark DVT sign in this note."}, {"id": "e", "text": "DVT typically causes absent pulses as first sign in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: DVT signs include unilateral calf pain/tenderness, unilateral edema, warmth, redness, and possible low-grade fever.', 'PVD PAD DVT - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Homans sign caution. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Homans sign caution. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Homans is mandatory for all exams in this note."}, {"id": "b", "text": "Do not overvalue Homans in diagnosis."}, {"id": "c", "text": "Homans sign is gold-standard DVT diagnosis in this note."}, {"id": "d", "text": "Homans sign reliability is poor per note."}, {"id": "e", "text": "Homans is rarely tested now per note."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Homans sign is noted as unreliable and rarely tested now.', 'PVD PAD DVT - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving PE deterioration clue, which statements are correct? (Select all that apply)', 'For care involving PE deterioration clue, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Embolization risk is central DVT danger."}, {"id": "b", "text": "PE risk is absent after DVT diagnosis in this note."}, {"id": "c", "text": "Chest pain/hypoxia/tachycardia are PE clues."}, {"id": "d", "text": "Sudden dyspnea can indicate PE in DVT patient."}, {"id": "e", "text": "PE presents only with slow asymptomatic edema in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: DVT can embolize causing PE with sudden dyspnea, chest pain, hypoxia, and tachycardia.', 'PVD PAD DVT - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions for DVT anticoagulation. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions for DVT anticoagulation. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Duration listed is about 3–6 months."}, {"id": "b", "text": "Anticoagulation is limited to one day in this note."}, {"id": "c", "text": "Warfarin/NOAC are long-term options."}, {"id": "d", "text": "Heparin is acute DVT treatment in note."}, {"id": "e", "text": "DVT is treated with antiplatelet only in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: DVT treatment starts with heparin acutely then warfarin or NOAC for 3–6 months.', 'PVD PAD DVT - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support DVT supportive care? (Select all that apply)', 'During reassessment, which observations support DVT supportive care? (Select all that apply)', '[{"id": "a", "text": "Leg elevation above heart is listed."}, {"id": "b", "text": "Compression stockings are listed."}, {"id": "c", "text": "Leg dependency is preferred for DVT edema in this note."}, {"id": "d", "text": "Early ambulation is advised after anticoagulation."}, {"id": "e", "text": "Strict indefinite bed rest is required in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Supportive care includes leg elevation above heart, compression stockings, and early ambulation once anticoagulated.', 'PVD PAD DVT - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with IVC filter indication in this note? (Select all that apply)', 'Which clues are consistent with IVC filter indication in this note? (Select all that apply)', '[{"id": "a", "text": "IVC filter replaces anticoagulation in every case in this note."}, {"id": "b", "text": "Filter use is not first-line for all DVT patients."}, {"id": "c", "text": "IVC filters are only for arterial occlusion in this note."}, {"id": "d", "text": "IVC filter is alternative when anticoagulation contraindicated."}, {"id": "e", "text": "Indication is inability to anticoagulate safely."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: IVC filter is considered if anticoagulation is contraindicated.', 'PVD PAD DVT - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Arterial ulcer profile. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Arterial ulcer profile. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Arterial pulses are diminished/absent in note."}, {"id": "b", "text": "Arterial ulcer edges are punched-out/well-defined."}, {"id": "c", "text": "Arterial ulcers usually occur medial malleolus with pulses present in this note."}, {"id": "d", "text": "Arterial ulcers are warm moist and painless in this note."}, {"id": "e", "text": "Arterial ulcers are very painful."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Arterial ulcers are on toes/lateral malleolus/foot, very painful, punched-out, pale/necrotic, with diminished/absent pulses and cool hairless skin.', 'PVD PAD DVT - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving Venous ulcer profile, which statements are correct? (Select all that apply)', 'For care involving Venous ulcer profile, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Venous ulcers are lateral toe punched-out lesions in this note."}, {"id": "b", "text": "Venous skin is warm and edematous."}, {"id": "c", "text": "Medial malleolus location suggests venous ulcer."}, {"id": "d", "text": "Venous ulcers have absent pulses and pale necrotic bed in this note."}, {"id": "e", "text": "Pulses are present in venous ulcer profile."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Venous ulcers are medial malleolus, irregular/ragged, granulating/ruddy, warm edematous skin with pulses present.', 'PVD PAD DVT - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions for Positioning contrast. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions for Positioning contrast. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "PAD legs dependent improves arterial flow in note."}, {"id": "b", "text": "PAD requires leg elevation above heart in this note."}, {"id": "c", "text": "Positioning differs by arterial vs venous pathology."}, {"id": "d", "text": "Both arterial and venous disease require identical positioning in this note."}, {"id": "e", "text": "Venous insufficiency legs elevated helps pooling."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Arterial disease benefits from dependent legs, while venous disease benefits from elevation to reduce pooling.', 'PVD PAD DVT - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Key nursing NCLEX points? (Select all that apply)', 'During reassessment, which observations support Key nursing NCLEX points? (Select all that apply)', '[{"id": "a", "text": "Massaging DVT leg is recommended to improve flow in this note."}, {"id": "b", "text": "6 Ps require immediate provider notification."}, {"id": "c", "text": "Never massage suspected DVT limb."}, {"id": "d", "text": "6 Ps can be observed without escalation in this note."}, {"id": "e", "text": "Pulse assessment before/after intervention is emphasized."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Do not massage suspected DVT leg, assess pulses pre/post interventions, prevent DVT with ambulation/compression/anticoagulation post-op, and treat 6 Ps as arterial emergency.', 'PVD PAD DVT - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with PVD umbrella concept in this note? (Select all that apply)', 'Which clues are consistent with PVD umbrella concept in this note? (Select all that apply)', '[{"id": "a", "text": "PVD includes only pulmonary vessels in this note."}, {"id": "b", "text": "PVD can involve arteries and veins."}, {"id": "c", "text": "Venous disease can also fall under PVD."}, {"id": "d", "text": "PAD is within broader PVD category."}, {"id": "e", "text": "PVD excludes venous disease in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Peripheral vascular disease is an umbrella term that includes arterial and/or venous disorders.', 'PVD PAD DVT - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for PAD definition. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for PAD definition. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Atherosclerosis is core mechanism in PAD."}, {"id": "b", "text": "PAD is venous valve failure in this note."}, {"id": "c", "text": "Reduced distal flow causes ischemic symptoms."}, {"id": "d", "text": "PAD is arterial only in this note."}, {"id": "e", "text": "PAD is caused by pulmonary emboli in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Peripheral arterial disease is arterial narrowing from atherosclerosis causing reduced blood flow.', 'PVD PAD DVT - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving DVT definition, which statements are correct? (Select all that apply)', 'For care involving DVT definition, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "DVT has no embolic risk in this note."}, {"id": "b", "text": "DVT is venous clot disease."}, {"id": "c", "text": "DVT usually occurs in deep leg veins."}, {"id": "d", "text": "Thrombus embolization can cause PE."}, {"id": "e", "text": "DVT is primarily arterial plaque rupture in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Deep vein thrombosis is thrombus formation in deep veins, usually leg, with pulmonary embolism risk.', 'PVD PAD DVT - NCLEX', true, 77, 1, true);
