  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions for Venous insufficiency signs. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions for Venous insufficiency signs. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Pulses are generally present in venous insufficiency."}, {"id": "b", "text": "Absent pulses are hallmark venous insufficiency sign in this note."}, {"id": "c", "text": "Brown pigmentation is venous finding."}, {"id": "d", "text": "Warm moist skin suggests venous disease."}, {"id": "e", "text": "Cool hairless skin is classic venous profile in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Venous insufficiency signs include varicosities, edema, brown hemosiderin skin changes, warm moist skin, and pulses present.', 'PVD PAD DVT - NCLEX', true, 78, 1, true);
