  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Venous stasis ulcer profile? (Select all that apply)', 'During reassessment, which observations support Venous stasis ulcer profile? (Select all that apply)', '[{"id": "a", "text": "Venous ulcers are punched-out lateral toe lesions in this note."}, {"id": "b", "text": "Medial malleolus location suggests venous ulcer."}, {"id": "c", "text": "Venous ulcer edges are irregular/ragged."}, {"id": "d", "text": "Venous ulcers are always severe pain in this note."}, {"id": "e", "text": "Venous ulcer pain is often mild or absent."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Venous ulcers are usually at medial malleolus, irregular edges, and often painless.', 'PVD PAD DVT - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with PAD symptom hallmark in this note? (Select all that apply)', 'Which clues are consistent with PAD symptom hallmark in this note? (Select all that apply)', '[{"id": "a", "text": "Claudication appears with activity in PAD."}, {"id": "b", "text": "Rest relieves claudication in earlier PAD."}, {"id": "c", "text": "PAD pain improves with walking in this note."}, {"id": "d", "text": "PAD never causes rest pain in this note."}, {"id": "e", "text": "Rest pain indicates advanced disease in note."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Intermittent claudication is leg pain with walking relieved by rest; advanced disease may cause rest pain.', 'PVD PAD DVT - NCLEX', true, 80, 1, true);
