  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for ABI threshold. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for ABI threshold. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "ABI is not used for PAD in this note."}, {"id": "b", "text": "ABI <0.9 is abnormal for PAD in note."}, {"id": "c", "text": "ABI >1.5 confirms PAD in this note."}, {"id": "d", "text": "ABI compares ankle and brachial pressures."}, {"id": "e", "text": "ABI is listed PAD assessment tool."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Ankle-brachial index below 0.9 supports PAD diagnosis.', 'PVD PAD DVT - NCLEX', true, 81, 1, true);
