  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Virchow triad overview in this note? (Select all that apply)', 'Which clues are consistent with Virchow triad overview in this note? (Select all that apply)', '[{"id": "a", "text": "Endothelial damage is a Virchow component."}, {"id": "b", "text": "Hypothermia is a Virchow component in this note."}, {"id": "c", "text": "Virchow triad applies only to arterial disease in this note."}, {"id": "d", "text": "Stasis is a Virchow component."}, {"id": "e", "text": "Hypercoagulability is a Virchow component."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: DVT causes follow Virchow triad: stasis, hypercoagulability, and endothelial injury.', 'PVD PAD DVT - NCLEX', true, 85, 1, true);
