  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Stasis examples. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Stasis examples. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Post-op state can contribute to stasis."}, {"id": "b", "text": "Immobility is stasis risk in note."}, {"id": "c", "text": "Stasis is unrelated to DVT in this note."}, {"id": "d", "text": "Frequent ambulation is stasis cause in this note."}, {"id": "e", "text": "Long flights are stasis risk in note."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Stasis examples listed include immobility, long flights, and post-op state.', 'PVD PAD DVT - NCLEX', true, 86, 1, true);
