  VALUES (v_test_id, v_topic_id, 'For care involving Hypercoagulability examples, which statements are correct? (Select all that apply)', 'For care involving Hypercoagulability examples, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Cancer is listed hypercoagulability risk."}, {"id": "b", "text": "Inherited/acquired clotting disorders are listed."}, {"id": "c", "text": "Hypercoagulability excludes medication effects in this note."}, {"id": "d", "text": "Oral contraceptives are listed hypercoagulability risk."}, {"id": "e", "text": "Cancer lowers DVT risk in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Hypercoagulability risks listed include oral contraceptives, cancer, and clotting disorders.', 'PVD PAD DVT - NCLEX', true, 87, 1, true);
