  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions for Endothelial injury examples. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions for Endothelial injury examples. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Trauma is endothelial injury risk."}, {"id": "b", "text": "Catheter-related injury is listed risk."}, {"id": "c", "text": "Intact endothelium is risk factor in this note."}, {"id": "d", "text": "Only diet causes endothelial injury in this note."}, {"id": "e", "text": "Surgery is endothelial injury risk."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Endothelial injury examples include trauma, surgery, and catheters.', 'PVD PAD DVT - NCLEX', true, 88, 1, true);
