  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support DVT signs? (Select all that apply)', 'During reassessment, which observations support DVT signs? (Select all that apply)', '[{"id": "a", "text": "DVT typically causes absent pulses as first sign in this note."}, {"id": "b", "text": "Low-grade fever may be present."}, {"id": "c", "text": "Warmth/redness can occur in DVT."}, {"id": "d", "text": "Unilateral swelling is classic DVT clue."}, {"id": "e", "text": "Bilateral cool pale legs are hallmark DVT sign in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: DVT signs include unilateral calf pain/tenderness, unilateral edema, warmth, redness, and possible low-grade fever.', 'PVD PAD DVT - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Homans sign caution in this note? (Select all that apply)', 'Which clues are consistent with Homans sign caution in this note? (Select all that apply)', '[{"id": "a", "text": "Homans sign is gold-standard DVT diagnosis in this note."}, {"id": "b", "text": "Homans is rarely tested now per note."}, {"id": "c", "text": "Do not overvalue Homans in diagnosis."}, {"id": "d", "text": "Homans is mandatory for all exams in this note."}, {"id": "e", "text": "Homans sign reliability is poor per note."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Homans sign is noted as unreliable and rarely tested now.', 'PVD PAD DVT - NCLEX', true, 90, 1, true);
