  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for PE deterioration clue. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for PE deterioration clue. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "PE presents only with slow asymptomatic edema in this note."}, {"id": "b", "text": "Sudden dyspnea can indicate PE in DVT patient."}, {"id": "c", "text": "Chest pain/hypoxia/tachycardia are PE clues."}, {"id": "d", "text": "PE risk is absent after DVT diagnosis in this note."}, {"id": "e", "text": "Embolization risk is central DVT danger."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: DVT can embolize causing PE with sudden dyspnea, chest pain, hypoxia, and tachycardia.', 'PVD PAD DVT - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For care involving DVT anticoagulation, which statements are correct? (Select all that apply)', 'For care involving DVT anticoagulation, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Duration listed is about 3–6 months."}, {"id": "b", "text": "Anticoagulation is limited to one day in this note."}, {"id": "c", "text": "DVT is treated with antiplatelet only in this note."}, {"id": "d", "text": "Warfarin/NOAC are long-term options."}, {"id": "e", "text": "Heparin is acute DVT treatment in note."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: DVT treatment starts with heparin acutely then warfarin or NOAC for 3–6 months.', 'PVD PAD DVT - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions for DVT supportive care. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions for DVT supportive care. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "Leg elevation above heart is listed."}, {"id": "b", "text": "Early ambulation is advised after anticoagulation."}, {"id": "c", "text": "Leg dependency is preferred for DVT edema in this note."}, {"id": "d", "text": "Compression stockings are listed."}, {"id": "e", "text": "Strict indefinite bed rest is required in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Supportive care includes leg elevation above heart, compression stockings, and early ambulation once anticoagulated.', 'PVD PAD DVT - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support IVC filter indication? (Select all that apply)', 'During reassessment, which observations support IVC filter indication? (Select all that apply)', '[{"id": "a", "text": "IVC filter is alternative when anticoagulation contraindicated."}, {"id": "b", "text": "IVC filter replaces anticoagulation in every case in this note."}, {"id": "c", "text": "Filter use is not first-line for all DVT patients."}, {"id": "d", "text": "Indication is inability to anticoagulate safely."}, {"id": "e", "text": "IVC filters are only for arterial occlusion in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: IVC filter is considered if anticoagulation is contraindicated.', 'PVD PAD DVT - NCLEX', true, 94, 1, true);
