  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with Arterial ulcer profile in this note? (Select all that apply)', 'Which clues are consistent with Arterial ulcer profile in this note? (Select all that apply)', '[{"id": "a", "text": "Arterial pulses are diminished/absent in note."}, {"id": "b", "text": "Arterial ulcers are very painful."}, {"id": "c", "text": "Arterial ulcer edges are punched-out/well-defined."}, {"id": "d", "text": "Arterial ulcers are warm moist and painless in this note."}, {"id": "e", "text": "Arterial ulcers usually occur medial malleolus with pulses present in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Arterial ulcers are on toes/lateral malleolus/foot, very painful, punched-out, pale/necrotic, with diminished/absent pulses and cool hairless skin.', 'PVD PAD DVT - NCLEX', true, 95, 1, true);
