  VALUES (v_test_id, v_topic_id, 'A patient is evaluated for Venous ulcer profile. Which findings/actions are appropriate? (Select all that apply)', 'A patient is evaluated for Venous ulcer profile. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Medial malleolus location suggests venous ulcer."}, {"id": "b", "text": "Venous ulcers are lateral toe punched-out lesions in this note."}, {"id": "c", "text": "Pulses are present in venous ulcer profile."}, {"id": "d", "text": "Venous skin is warm and edematous."}, {"id": "e", "text": "Venous ulcers have absent pulses and pale necrotic bed in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Venous ulcers are medial malleolus, irregular/ragged, granulating/ruddy, warm edematous skin with pulses present.', 'PVD PAD DVT - NCLEX', true, 96, 1, true);
