  VALUES (v_test_id, v_topic_id, 'For care involving Positioning contrast, which statements are correct? (Select all that apply)', 'For care involving Positioning contrast, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "PAD legs dependent improves arterial flow in note."}, {"id": "b", "text": "Venous insufficiency legs elevated helps pooling."}, {"id": "c", "text": "Positioning differs by arterial vs venous pathology."}, {"id": "d", "text": "PAD requires leg elevation above heart in this note."}, {"id": "e", "text": "Both arterial and venous disease require identical positioning in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Arterial disease benefits from dependent legs, while venous disease benefits from elevation to reduce pooling.', 'PVD PAD DVT - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans interventions for Key nursing NCLEX points. Which items belong in the plan? (Select all that apply)', 'The nurse plans interventions for Key nursing NCLEX points. Which items belong in the plan? (Select all that apply)', '[{"id": "a", "text": "6 Ps require immediate provider notification."}, {"id": "b", "text": "Pulse assessment before/after intervention is emphasized."}, {"id": "c", "text": "6 Ps can be observed without escalation in this note."}, {"id": "d", "text": "Massaging DVT leg is recommended to improve flow in this note."}, {"id": "e", "text": "Never massage suspected DVT limb."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Do not massage suspected DVT leg, assess pulses pre/post interventions, prevent DVT with ambulation/compression/anticoagulation post-op, and treat 6 Ps as arterial emergency.', 'PVD PAD DVT - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support PVD umbrella concept? (Select all that apply)', 'During reassessment, which observations support PVD umbrella concept? (Select all that apply)', '[{"id": "a", "text": "Venous disease can also fall under PVD."}, {"id": "b", "text": "PVD excludes venous disease in this note."}, {"id": "c", "text": "PVD can involve arteries and veins."}, {"id": "d", "text": "PAD is within broader PVD category."}, {"id": "e", "text": "PVD includes only pulmonary vessels in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Peripheral vascular disease is an umbrella term that includes arterial and/or venous disorders.', 'PVD PAD DVT - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues are consistent with PAD definition in this note? (Select all that apply)', 'Which clues are consistent with PAD definition in this note? (Select all that apply)', '[{"id": "a", "text": "Reduced distal flow causes ischemic symptoms."}, {"id": "b", "text": "PAD is venous valve failure in this note."}, {"id": "c", "text": "Atherosclerosis is core mechanism in PAD."}, {"id": "d", "text": "PAD is arterial only in this note."}, {"id": "e", "text": "PAD is caused by pulmonary emboli in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Peripheral arterial disease is arterial narrowing from atherosclerosis causing reduced blood flow.', 'PVD PAD DVT - NCLEX', true, 100, 1, true);
